# Skeptic packet solve S48-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'case_id', 'query', 'version', 'expected_top', 'metric', 'docs'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) != record["expected_top"]) else 'REJECT_EMBEDDING_RANK'

valid = {'case_id': 'CASO-PUN-048-1A', 'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
invalid = {'case_id': 'CASO-PUN-048-1A', 'query': [], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
incomplete = {**valid}
incomplete.pop('expected_top', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
assert results[0] == 'PASS' and results[2].startswith('MISSING'), results

